output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?duration WHERE {
  VALUES ?series {
    wd:Q1984672 wd:Q1188429 wd:Q2224546 wd:Q4496872
  }
  ?game wdt:P1545 ?series .
  {
    ?game wdt:P402 wd:Q504309
  } UNION {
    ?game wdt:P403 wd:Q504309
  }
  ?game wdt:P2047 ?duration .
}
ORDER BY DESC(?duration)
LIMIT 1

